+/// Map Result.ColumnData type to writer.DataType
+fn columnDataToLanceType(data: Result.ColumnData) writer.DataType {
+    return switch (data) {
+        .int64, .timestamp_s, .timestamp_ms, .timestamp_us, .timestamp_ns, .date64 => .int64,
+        .int32, .date32 => .int32,
+        .float64 => .float64,
+        .float32 => .float32,
+        .bool_ => .bool,
+        .string => .string,
+    };
+}
