+
+    var index = FlatIndex(4).init(allocator, .l2);
+    defer index.deinit();
+
+    // Add some vectors
+    try index.add(.{ 1.0, 0.0, 0.0, 0.0 });
+    try index.add(.{ 0.0, 1.0, 0.0, 0.0 });
+    try index.add(.{ 0.0, 0.0, 1.0, 0.0 });
+    try index.add(.{ 0.5, 0.5, 0.0, 0.0 });
